fixed_code:
use std::sync::Mutex;
use std::sync::Arc;
use std::collections::HashMap;

type Db = Arc<Mutex<HashMap<String, String>>>;

async fn get_or_fetch(db: &Db, key: &str) -> String {
    // Check the cache in a limited scope — release lock before awaiting
    {
        let guard = db.lock().unwrap();
        if let Some(v) = guard.get(key) {
            return v.clone();
        }
    }  // guard dropped here — lock released before any await

    let fetched = fetch_from_remote(key).await;  // no lock held

    // Re-acquire to insert the result
    db.lock().unwrap().insert(key.to_owned(), fetched.clone());
    fetched
}

async fn fetch_from_remote(_key: &str) -> String {
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    String::from("fetched")
}

#[tokio::main]
async fn main() {
    let db: Db = Arc::new(Mutex::new(HashMap::new()));
    let result = get_or_fetch(&db, "hello").await;
    println!("{}", result);
}

