use tokio::sync::Mutex;
use std::sync::Arc;

struct Stats {
    requests: u64,
    errors: u64,
}

async fn handle_request(stats: Arc<Mutex<Stats>>, is_error: bool) {
    tokio::time::sleep(tokio::time::Duration::from_micros(100)).await;
    let mut s = stats.lock().await;
    s.requests += 1;
    if is_error { s.errors += 1; }
}

#[tokio::main]
async fn main() {
    let stats = Arc::new(Mutex::new(Stats { requests: 0, errors: 0 }));
    let mut handles = vec![];
    for i in 0..100 {
        let s = Arc::clone(&stats);
        handles.push(tokio::spawn(handle_request(s, i % 10 == 0)));
    }
    for h in handles { h.await.unwrap(); }
    let s = stats.lock().await;
    println!("requests={} errors={}", s.requests, s.errors);
}

error_message:
// Compiles fine. The issue is performance: all tasks serialize on the
// Mutex even though the actual critical section (++ increment) is tiny.
// For counters, atomics are far faster than a mutex.

fixed_code:
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

struct Stats {
    requests: AtomicU64,
    errors: AtomicU64,
}

impl Stats {
    fn new() -> Self {
        Stats { requests: AtomicU64::new(0), errors: AtomicU64::new(0) }
    }
}

async fn handle_request(stats: Arc<Stats>, is_error: bool) {
    tokio::time::sleep(tokio::time::Duration::from_micros(100)).await;
    // No lock needed — atomic operations are wait-free
    stats.requests.fetch_add(1, Ordering::Relaxed);
    if is_error {
        stats.errors.fetch_add(1, Ordering::Relaxed);
    }
}

#[tokio::main]
async fn main() {
    let stats = Arc::new(Stats::new());
    let mut handles = vec![];
    for i in 0..100 {
        let s = Arc::clone(&stats);
        handles.push(tokio::spawn(handle_request(s, i % 10 == 0)));
    }
    for h in handles { h.await.unwrap(); }
    println!("requests={} errors={}",
        stats.requests.load(Ordering::Relaxed),
        stats.errors.load(Ordering::Relaxed));
}

