// Problematic: Arc<Mutex<HashMap>> shared directly across tasks
use std::sync::Arc;
use tokio::sync::Mutex;
use std::collections::HashMap;

// Every caller must lock the whole map even for unrelated keys
async fn get(map: &Arc<Mutex<HashMap<String, i32>>>, key: &str) -> Option<i32> {
    map.lock().await.get(key).copied()
}

async fn set(map: &Arc<Mutex<HashMap<String, i32>>>, key: String, val: i32) {
    map.lock().await.insert(key, val);
}

#[tokio::main]
async fn main() {
    let map: Arc<Mutex<HashMap<String, i32>>> = Arc::new(Mutex::new(HashMap::new()));
    set(&map, String::from("x"), 42).await;
    println!("{:?}", get(&map, "x").await);
}

error_message:
// Compiles correctly. This is a design issue: Arc<Mutex<HashMap>> works
// but every operation acquires an exclusive lock over the ENTIRE map,
// limiting concurrency even when different tasks access different keys.

fixed_code:
use tokio::sync::{mpsc, oneshot};
use std::collections::HashMap;

#[derive(Debug)]
enum MapCmd {
    Get { key: String, reply: oneshot::Sender<Option<i32>> },
    Set { key: String, value: i32 },
}

// Actor: owns the HashMap exclusively — no locking needed
async fn map_actor(mut rx: mpsc::Receiver<MapCmd>) {
    let mut store: HashMap<String, i32> = HashMap::new();
    while let Some(cmd) = rx.recv().await {
        match cmd {
            MapCmd::Get { key, reply } => {
                let _ = reply.send(store.get(&key).copied());
            }
            MapCmd::Set { key, value } => {
                store.insert(key, value);
            }
        }
    }
}

#[derive(Clone)]
struct MapHandle(mpsc::Sender<MapCmd>);

impl MapHandle {
    fn new() -> (Self, tokio::task::JoinHandle<()>) {
        let (tx, rx) = mpsc::channel(64);
        let handle = tokio::spawn(map_actor(rx));
        (MapHandle(tx), handle)
    }

    async fn get(&self, key: &str) -> Option<i32> {
        let (tx, rx) = oneshot::channel();
        self.0.send(MapCmd::Get { key: key.to_owned(), reply: tx }).await.unwrap();
        rx.await.unwrap()
    }

    async fn set(&self, key: String, value: i32) {
        self.0.send(MapCmd::Set { key, value }).await.unwrap();
    }
}

#[tokio::main]
async fn main() {
    let (map, _actor) = MapHandle::new();
    map.set(String::from("x"), 42).await;
    println!("{:?}", map.get("x").await);
    // MapHandle is Clone — share it freely across tasks
}

