// No compile error. worker() never waits for a config change —
// it polls on a timer instead of reacting to actual updates,
// leading to unnecessary processing and potential missed updates.

fixed_code:
use tokio::sync::watch;

#[derive(Clone, Debug)]
struct Config { rate_limit: u32 }

async fn worker(mut cfg_rx: watch::Receiver<Config>, id: u32) {
    // Process the initial config once on startup
    let cfg = cfg_rx.borrow().clone();
    println!("worker {} initial rate_limit={}", id, cfg.rate_limit);

    loop {
        // Wait for the NEXT change — suspends until config is updated
        match cfg_rx.changed().await {
            Ok(()) => {
                // borrow_and_update() marks the value as seen (resets changed flag)
                let cfg = cfg_rx.borrow_and_update().clone();
                println!("worker {} updated rate_limit={}", id, cfg.rate_limit);
                // Apply new config — no timer polling needed
            }
            Err(_) => {
                println!("worker {} config sender dropped, stopping", id);
                break;
            }
        }
    }
}

#[tokio::main]
async fn main() {
    let (tx, rx) = watch::channel(Config { rate_limit: 100 });
    let t = tokio::spawn(worker(rx, 1));

    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
    tx.send(Config { rate_limit: 200 }).unwrap();
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
    tx.send(Config { rate_limit: 300 }).unwrap();

    drop(tx);  // causes changed().await to return Err
    t.await.unwrap();
}

