use std::sync::{Arc, RwLock};
use std::collections::HashMap;

async fn lookup_and_log(cache: Arc<RwLock<HashMap<u64, String>>>, key: u64) {
    // Clone out of the critical section before any await point
    let value = {
        let guard = cache.read().unwrap();
        guard.get(&key).cloned()
    };  // guard dropped here

    log_to_remote(&key, &value).await;  // no lock held
}

async fn log_to_remote(key: &u64, value: &Option<String>) {
    tokio::time::sleep(tokio::time::Duration::from_millis(1)).await;
    println!("logged key={} value={:?}", key, value);
}

#[tokio::main]
async fn main() {
    let cache = Arc::new(RwLock::new(HashMap::from([
        (1u64, String::from("one")),
        (2u64, String::from("two")),
    ])));
    lookup_and_log(Arc::clone(&cache), 1).await;
    lookup_and_log(Arc::clone(&cache), 99).await;
}
